interface FormFields {
  name?: string;
  email?: string;
  age?: number;
}

function buildForm(fields: FormFields): Required<FormFields> | string {
  const missing: string[] = [];
  if (!fields.name) missing.push("name");
  if (!fields.email) missing.push("email");
  if (fields.age === undefined) missing.push("age");

  if (missing.length > 0) {
    return `Missing fields: ${missing.join(", ")}`;
  }

  return fields as Required<FormFields>;
}

const result1 = buildForm({ name: "Alice", email: "a@b.com", age: 30 });
console.log(typeof result1 === "string" ? result1 : `${result1.name}, ${result1.email}, ${result1.age}`);

const result2 = buildForm({ name: "Bob" });
console.log(result2);

