interface AppConfig {
  apiUrl: string | null;
  port: number | null;
  debug: boolean | null;
}

function getConfigValue<K extends keyof AppConfig>(
  config: AppConfig,
  key: K,
  fallback: NonNullable<AppConfig[K]>
): NonNullable<AppConfig[K]> {
  const value = config[key];
  return (value !== null ? value : fallback) as NonNullable<AppConfig[K]>;
}

const config: AppConfig = { apiUrl: "https://api.com", port: null, debug: null };

